// Construct the IronPigDatum as Plutus constr(0, [...])
export function buildIronPigDatum(
  goalUsd: number,
  ownerVkh: string,
  pythPolicyId: string = PYTH_POLICY_ID,
  adaFeedId: string = ADA_USD_FEED_ID
) {
  return {
    alternative: 0,
    fields: [
      goalUsd * MICRO_USD_PER_USD,
      ownerVkh,
      pythPolicyId,
      adaFeedId,
    ],
  };
}

